package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.BedServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/beds")public class BedListServlet extends HttpServlet{private final BedService s;public BedListServlet(){this(new BedServiceImpl());}public BedListServlet(BedService x){s=x;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int p=Math.max(1,AdmissionRequest.number(q.getParameter("page"),1)),z=Math.max(1,AdmissionRequest.number(q.getParameter("size"),10));q.setAttribute("bedPage",s.listBeds(new PageRequest(p,z,q.getParameter("search")),AdmissionRequest.id(q.getParameter("roomId")),q.getParameter("status")));q.getRequestDispatcher("/WEB-INF/views/admin/beds/list.jsp").forward(q,r);}}
